try {
  let data = $input.item.json.text || $input.item.json;
  if (typeof data === 'string' && data.startsWith('```json')) {
    data = data.replace(/```json/g, '').replace(/```/g, '');
  }
  const parsed = typeof data === 'string' ? JSON.parse(data) : data;

  // 1. Converter data DD/MM/YYYY para YYYY-MM-DD
  if (parsed.date && typeof parsed.date === 'string' && parsed.date.includes('/')) {
    const parts = parsed.date.split('/');
    if (parts.length === 3) {
      parsed.date = `${parts[2]}-${parts[1].padStart(2, '0')}-${parts[0].padStart(2, '0')}`;
    }
  }
  if (!parsed.date || (typeof parsed.date === 'string' && parsed.date.trim() === '')) {
    parsed.date = new Date().toISOString().split('T')[0];
  }

  // 2. Amount
  let val = parsed.amount;
  if (typeof val === 'string') {
    val = parseFloat(val.replace(',', '.'));
  }
  parsed.amount = val ? -Math.abs(val) : 0;

  // 3. Category
  if (!parsed.category || (typeof parsed.category === 'string' && parsed.category.trim() === '')) {
    parsed.category = 'Outros';
  }

  // 4. Description
  if (!parsed.description || (typeof parsed.description === 'string' && parsed.description.trim() === '')) {
    parsed.description = 'Sem descrição';
  }

  // 5. Payee (Beneficiário)
  if (!parsed.payee || (typeof parsed.payee === 'string' && parsed.payee.trim() === '')) {
    parsed.payee = 'Não identificado';
  }

  // 6. Account
  if (!parsed.account || (typeof parsed.account === 'string' && parsed.account.trim() === '')) {
    parsed.account = 'CAIXA_TESOURARIA';
  }

  // 7. Colunas exatas do Supabase baseadas no SQL do usuário
  parsed.type = 'saida';
  parsed.status = 'pendente';
  parsed.notes = 'source: ocr';

  return parsed;
} catch(e) {
  return {
    date: new Date().toISOString().split('T')[0],
    description: 'Erro de Leitura OCR',
    amount: 0,
    category: 'Outros',
    account: 'CAIXA_TESOURARIA',
    payee: 'Não identificado',
    type: 'saida',
    status: 'pendente',
    notes: 'source: ocr'
  };
}
